import { NextRequest, NextResponse } from 'next/server';
import { metricsCollector } from '@/lib/monitoring/metrics';
import { withRequestTracking } from '@/lib/monitoring/correlation-middleware';

async function metricsHandler(request: NextRequest) {
  try {
    // Get all metrics
    const counters = Object.fromEntries(metricsCollector.getCounters());
    const gauges = Object.fromEntries(metricsCollector.getGauges());
    const histograms = Object.fromEntries(metricsCollector.getHistograms());
    
    // Get histogram statistics
    const histogramStats: Record<string, any> = {};
    for (const [name] of metricsCollector.getHistograms()) {
      const stats = metricsCollector.getHistogramStats(name);
      if (stats) {
        histogramStats[name] = stats;
      }
    }

    const metricsData = {
      timestamp: new Date().toISOString(),
      counters,
      gauges,
      histograms: histogramStats,
      raw_histograms: histograms // Include raw data for debugging
    };

    // Check if Prometheus format is requested
    const acceptHeader = request.headers.get('accept');
    if (acceptHeader?.includes('text/plain') || request.nextUrl.searchParams.get('format') === 'prometheus') {
      // Return Prometheus format
      const prometheusMetrics = formatPrometheusMetrics(counters, gauges, histogramStats);
      return new NextResponse(prometheusMetrics, {
        headers: {
          'Content-Type': 'text/plain; charset=utf-8'
        }
      });
    }

    // Return JSON format by default
    return NextResponse.json(metricsData);
    
  } catch (error) {
    return NextResponse.json(
      {
        error: 'Failed to retrieve metrics',
        message: error instanceof Error ? error.message : String(error),
        timestamp: new Date().toISOString()
      },
      { status: 500 }
    );
  }
}

function formatPrometheusMetrics(
  counters: Record<string, number>,
  gauges: Record<string, number>,
  histogramStats: Record<string, any>
): string {
  const lines: string[] = [];
  
  // Add counters
  for (const [name, value] of Object.entries(counters)) {
    const cleanName = name.replace(/[{}]/g, '').replace(/=/g, '_');
    lines.push(`# TYPE ${cleanName} counter`);
    lines.push(`${cleanName} ${value}`);
  }
  
  // Add gauges
  for (const [name, value] of Object.entries(gauges)) {
    const cleanName = name.replace(/[{}]/g, '').replace(/=/g, '_');
    lines.push(`# TYPE ${cleanName} gauge`);
    lines.push(`${cleanName} ${value}`);
  }
  
  // Add histogram statistics as gauges
  for (const [name, stats] of Object.entries(histogramStats)) {
    const cleanName = name.replace(/[{}]/g, '').replace(/=/g, '_');
    lines.push(`# TYPE ${cleanName}_count gauge`);
    lines.push(`${cleanName}_count ${stats.count}`);
    lines.push(`# TYPE ${cleanName}_avg gauge`);
    lines.push(`${cleanName}_avg ${stats.avg}`);
    lines.push(`# TYPE ${cleanName}_p50 gauge`);
    lines.push(`${cleanName}_p50 ${stats.p50}`);
    lines.push(`# TYPE ${cleanName}_p95 gauge`);
    lines.push(`${cleanName}_p95 ${stats.p95}`);
    lines.push(`# TYPE ${cleanName}_p99 gauge`);
    lines.push(`${cleanName}_p99 ${stats.p99}`);
  }
  
  return lines.join('\n') + '\n';
}

export const GET = withRequestTracking(metricsHandler, '/api/metrics');